sys_script_client.script:
function onLoad(control, oldValue, newValue, isLoading, isTemplate) {
	//Run on change and on load, even if value is empty.

	var i, gaValidateValue, intervalValidatingMsg, errorMsg;

	intervalValidatingMsg = showValidatingMsg();

	gaValidateValue = new GlideAjax('x_taniu_tan_core.ConfiguredSensorAJAX');
	gaValidateValue.addParam('sysparm_name', 'checkAllConfiguredSensorParamValues');
	gaValidateValue.addParam('configured_sensor_sys_id', g_form.getUniqueValue());
	gaValidateValue.getXMLAnswer(function(answer) {
		var isValid, helpStrings, invalidParamKeys;
		stopValidatingMsg(intervalValidatingMsg);

		answer = JSON.parse(answer);
		isValid = answer.valid;
		invalidParamKeys = answer.invalid_param_keys;
		helpStrings = answer.help_strings;

		//Remove any existing field messages
		g_form.clearMessages();

		if (isValid) {
			return; //Stop here if all is well.
		}

		errorMsg = 'At least one of the Configured Sensor Parameters associated with this Configured Sensor could not be validated.';
		if (invalidParamKeys && invalidParamKeys.length > 0) {
			errorMsg += '<div>';
			errorMsg += '<p><a href="#" onclick="javascript: jQuery(this.parentNode).next().toggle(200);">Show more</a></p>';
			errorMsg += '<div style="display: none;">';
			errorMsg += 'Parameter keys with invalid values:\n'
			errorMsg += '<ul style="list-style: disc">';
			for (i = 0; i < invalidParamKeys.length; i++) {
				errorMsg += '<li>' + invalidParamKeys[i] + '</li>';
			}
			errorMsg += '</ul>';
			errorMsg += '<p><i>You can use this Configured Sensor even if the Configured Parameters don\'t all pass validation, but do so at your own risk.</i></p>';
			errorMsg += '</div>';
			errorMsg += '</div>';
		}

		g_form.addErrorMessage(errorMsg);
	});

	function showValidatingMsg() {
		var intervalDots = {'count' : 1};
		intervalValidatingMsg = setInterval(function () {
			var i;
			var validatingMessage = 'Validating Configured Sensor Parameters';

			if (intervalDots.count >= 3) {
				intervalDots.count = 1;
			} else {
				intervalDots.count++;
			}

			for (i = 0; i < intervalDots.count; i++) {
				validatingMessage += '.';
			}

			g_form.clearMessages();
			g_form.addInfoMessage(validatingMessage);
		}, 170, intervalDots);
		return intervalValidatingMsg;
	}

	function stopValidatingMsg(intervalValidatingMsg) {
		clearInterval(intervalValidatingMsg);
	}
}
